import java.beans.*;
public class PropertyChangeDemo {
    public static void main(String[] args) {
        PropertyChangeSupport pcs = new PropertyChangeSupport(new Object());
        pcs.addPropertyChangeListener("name", evt ->
            System.out.println(evt.getOldValue() + "->" + evt.getNewValue())
        );
        pcs.firePropertyChange("name", "Alice", "Bob");
        pcs.firePropertyChange("age", 10, 20);  // different property, not heard
    }
}
